sql:
SELECT n.neighborhood_name
FROM neighborhoods n
WHERE n.borough = 'Downtown Toronto' AND n.population > (SELECT AVG(population) FROM neighborhoods);

external_knowledge:
- "zip codes" = postal codes;
- "rental whispers" = average rent;
- "house value mystiques" = median house value;
- "tales" = descriptions;
- "visual spectacles" = image URLs;
- "urban jewels" = neighborhoods;
- "city’s heart" = Downtown Toronto; 
- "from A to Z" = order by neighborhood names alphabetically.

sql:
SELECT AVG(average_rent) AS AverageRent
FROM neighborhoods
WHERE postal_code IN (
    SELECT postal_code
    FROM neighborhoods
    WHERE median_house_value = (
        SELECT MAX(median_house_value)
        FROM neighborhoods
    )
);

SELECT neighborhood_name, average_rent 
FROM neighborhoods 
WHERE borough = 'Bronx';
